import { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { Helmet } from 'react-helmet-async';
import Benefits from '../components/sections/Benefits';
import Features from '../components/sections/Features';
import Pricing from '../components/sections/Pricing';
import Steps from '../components/sections/Steps';
import FAQ from '../components/sections/FAQ';
import FinalCTA from '../components/sections/FinalCTA';
import api from '../services/api';
import { contentService } from '../services/cmsService';

const SECTION_COMPONENTS = {
  hero: null,
  benefits: Benefits,
  features: Features,
  pricing: Pricing,
  steps: Steps,
  faq: FAQ,
  cta: FinalCTA,
  default: null,
};

export default function DynamicPage() {
  const { slug } = useParams();
  const [page, setPage] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    if (!slug) {
      setError('No slug provided');
      setLoading(false);
      return;
    }

    setLoading(true);

    api.get(`/pages/${slug}`)
      .then(res => res.data)
      .then(pageData => {
        console.log('Page data:', pageData);
        if (pageData && (pageData.slug || pageData.id)) {
          setPage(pageData);
        } else if (pageData && pageData.error) {
          setError(pageData.error);
        } else {
          setError('Page not found');
        }
        setLoading(false);
      })
      .catch(err => {
        console.error('API Error:', err.response || err);
        const errorMsg = err.response?.data?.error || err.message || 'Cannot connect to API';
        setError(errorMsg);
        setLoading(false);
      });
  }, [slug]);

  const renderSection = (section, index) => {
    if (!section.isEnabled) return null;

    if (section.type === 'hero') {
      return (
        <section key={section.id || index} className="bg-yellow-500 text-white py-16 md:py-24">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
            {section.title && <h1 className="text-4xl md:text-5xl font-bold mb-6">{section.title}</h1>}
            {section.content && <p className="text-xl md:text-2xl text-yellow-100">{section.content}</p>}
          </div>
        </section>
      );
    }

    if (section.type === 'benefits') {
      return <Benefits key={section.id || index} />;
    }
    if (section.type === 'features') {
      return <Features key={section.id || index} />;
    }
    if (section.type === 'pricing') {
      return <Pricing key={section.id || index} />;
    }
    if (section.type === 'steps') {
      return <Steps key={section.id || index} />;
    }
    if (section.type === 'faq') {
      return <FAQ key={section.id || index} />;
    }
    if (section.type === 'cta') {
      return <FinalCTA key={section.id || index} />;
    }

    // Default section with cards
    return (
      <section key={section.id || index} className="py-12 md:py-16 bg-white">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          {section.title && <h2 className="text-3xl md:text-4xl font-bold mb-6 text-gray-800">{section.title}</h2>}
          {section.content && <div className="prose max-w-none text-gray-600 mb-8" dangerouslySetInnerHTML={{ __html: section.content }} />}
          {section.cards?.length > 0 && (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {section.cards.map((card) => (
                <div key={card.id} className="bg-gray-50 rounded-xl p-6">
                  {card.icon && <i className={`fas ${card.icon} text-2xl text-yellow-500 mb-3`}></i>}
                  {card.title && <h3 className="text-xl font-semibold text-gray-800 mb-2">{card.title}</h3>}
                  {card.content && <p className="text-gray-600">{card.content}</p>}
                </div>
              ))}
            </div>
          )}
        </div>
      </section>
    );
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-yellow-500"></div>
      </div>
    );
  }

  if (error || !page) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <h1 className="text-2xl font-bold text-gray-800 mb-2">Page non trouvée</h1>
          <p className="text-gray-600">{error || 'Cette page n\'existe pas ou n\'est pas publiée.'}</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-white">
      <Helmet>
        <title>{page.metaDescription || page.title || 'Page'}</title>
        {page.metaDescription && <meta name="description" content={page.metaDescription} />}
      </Helmet>
      {page.sections?.map(renderSection)}
    </div>
  );
}
